import numpy as np

def select_next_node(current_node, destination_node, unvisited_nodes, distance_matrix):
    max_difference = -1
    next_node = -1

    for node in unvisited_nodes:
        cur_to_node = distance_matrix[current_node][node]
        sorted_distances = np.sort(distance_matrix[node][unvisited_nodes])
        if len(sorted_distances) > 1:
            difference = sorted_distances[1] - cur_to_node
            if difference > max_difference:
                max_difference = difference
                next_node = node

    return next_node
